import { describe, it, expect } from "vitest";

describe("Claim Office — quote / premium calculation", () => {
  it.todo("empty item list → premium 5 G (processing fee only)");

  it.todo("single potion, newcomer (0 years), no modifiers → 49 G (40 base + 4 first-insurance + 5 fee)");

  it.todo("single amulet, newcomer (0 years), no modifiers → 71 G (60 base + 6 first-insurance + 5 fee)");

  it.todo("single staff, newcomer (0 years), no modifiers → 93 G (80 base + 8 first-insurance + 5 fee)");

  it.todo("single sword, newcomer (0 years), no modifiers → 115 G (100 base + 10 first-insurance + 5 fee)");

  it.todo("single rune component, newcomer → 33 G (25 base + 2.5 first-insurance + 5 fee, rounded up)");

  it.todo("2 runes (no building block) → 60 G base premium, premium 60 G (50 + 5 first-insurance + 5 fee)");

  it.todo("3 runes (building block applies) → 60 G base, premium 71 G (60 + 6 first-insurance + 5 fee)");

  it.todo("4 runes (no block — requires exactly 3) → 100 G base, premium 115 G (100 + 10 first-insurance + 5 fee)");

  it.todo("7 runes (1 block of 3 + 4 individuals) → 175 G base, premium 198 G (175 + 17.5 first-insurance + 5 fee, rounded up from 197.5)");

  it.todo("2 runes + 1 moonstone → no block (different types) → 75 G base, premium 88 G (75 + 7.5 + 5, rounded up from 87.5)");

  it.todo("3 runes + 3 moonstones → two separate blocks → 120 G base, premium 137 G (120 + 12 first-insurance + 5 fee)");

  it.todo("sword enchantment 4, not cursed → no high-enchantment surcharge → 115 G (boundary: below 5)");

  it.todo("sword enchantment exactly 5, not cursed → high-enchantment surcharge applies → 145 G (100 + 30 high-ench + 10 first-ins + 5 fee)");

  it.todo("cursed sword enchantment 5 → both curse and high-enchantment surcharges → 195 G (100 + 50 curse + 30 high-ench + 10 first-ins + 5 fee)");

  it.todo("customer with exactly 2 years, single plain sword → loyalty discount applies → 95 G (100 + 10 first-ins − 20 loyalty + 5 fee)");

  it.todo("customer with 1 year, single plain sword → no loyalty → 115 G (boundary: below 2 years)");

  it.todo("newcomer with cursed sword (steel, enchantment 3) → 165 G (100 base + 50 curse + 10 first-insurance + 5 fee) [E10 integration]");

  it.todo("cursed sword + plain amulet, newcomer → 231 G (160 policy base + 50 curse on sword only + 16 first-ins + 5 fee) [E2 modifier scope]");

  it.todo("long-standing customer (3 yrs), first quote in scenario, single plain sword → 95 G (no follow-up discount on first quote: 100 + 10 first-ins − 20 loyalty + 5 fee)");

  it.todo("long-standing customer's second quote in scenario: cursed sword enchantment 7 → 160 G (100 + 50 curse + 30 high-ench − 20 loyalty + 10 first-ins − 15 follow-up + 5 fee) [E11 integration]");
});

describe("Claim Office — claim / payout calculation", () => {
  it.todo("standard reimbursement: steel sword, enchantment 3, damage 500 G → payout 400 G (500 − 100 deductible)");

  it.todo("standard reimbursement: damaged rune (no enchantment, no material), damage 200 G → payout 100 G (200 − 100 deductible)");

  it.todo("dragon attack damages a sword (500 G) and an amulet (300 G) in one event → payout 600 G (each item gets its own 100 G deductible: 400 + 200)");

  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (dragon clause: full reimbursement, then 100 G deductible)");

  it.todo("dragon-material sword, enchantment exactly 8, damage 1000 G → payout 400 G (high-ench clause wins: 50% then deductible: 500 − 100)");

  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (both clauses apply; 50% rule wins: 500 − 100)");

  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (only high-enchantment clause: 50% then deductible: 500 − 100)");

  it.todo("policy covers two swords; claim has two sword damage entries → each treated separately with its own deductible (e.g. damages 500 and 300 → 400 + 200 = 600 G)");

  it.todo("payout rounding: dragon-material sword enchantment 9, damage 1001 G → payout 400 G (50% = 500.5, − 100 deductible = 400.5 → rounded down)");
});

describe("Claim Office CLI", () => {
  it.todo("CLI reads scenario JSON from stdin (customer + quote + claim) and writes {results: [{premium}, {payout}]} JSON to stdout with exit code 0");

  it.todo("CLI: empty steps array → writes {results: []} to stdout, exit code 0");

  it.todo("CLI: quote includes an item with an unknown type (e.g. broomstick) → exits non-zero, writes error description to stderr, no results on stdout");

  it.todo("CLI: claim references item type not present in the policy (e.g. amulet damage when only a sword is insured) → exits non-zero, writes error description to stderr");

  it.todo("CLI: claim references an item with an unknown type → exits non-zero, writes error description to stderr");

  it.todo("CLI: claim contains a damage entry with amount -200 → exits non-zero, writes error description to stderr");

  it.todo("CLI: damages array contains more entries of a type than the policy covers (e.g. two sword damages but only one sword insured) → exits non-zero, whole claim rejected");

  it.todo("CLI end-to-end: long-standing customer (3 yrs), two consecutive quotes for cursed sword (steel, ench 7) → second quote result is {premium: 160} [E11 scenario-scoped follow-up discount]");
});
